#include <stdio.h>

int main() {
    int values[8];
    int max;

    // Input: Enter 8 integers
    for (int i = 0; i < 8; i++) {
        scanf("%d", &values[i]);
    }

    // Initialize max with the first element
    max = values[0];

    // Find the maximum value in the array
    for (int i = 1; i < 8; i++) {
        if (values[i] > max) {
            max = values[i];
        }
    }

    // Output: Print the maximum value
    printf("%d\n", max);

    return 0;
}
